#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M,K; scanf("%d %d %d",&N,&M,&K);
        int all=1, firstM=1, x;
        for(int i=1;i<=N;i++){
            scanf("%d",&x);
            if(x==0){
                all=0;
                if(i<=M) firstM=0;
            }
        }
        if(all) printf("100\n");
        else if(firstM) printf("%d\n",K);
        else printf("0\n");
    }
    return 0;
}

