import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); K = int(next(it))
        all_one = True
        first_m_one = True
        for i in range(1, N+1):
            a = int(next(it))
            if a == 0:
                all_one = False
                if i <= M:
                    first_m_one = False
        if all_one:
            out.append('100')
        elif first_m_one:
            out.append(str(K))
        else:
            out.append('0')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

